mapper.insert:
insert into biz_finance_expense(
  expense_no, instrument_id, department_id, expense_type, amount,
  title, remark, expense_time, operator_user_id, create_time, update_time
) values (
  #{expenseNo}, #{instrumentId}, #{departmentId}, #{expenseType}, #{amount},
  #{title}, #{remark}, #{expenseTime}, #{operatorUserId}, #{createTime}, #{updateTime}
)

mapper.select:
select e.*, i.instrument_name, d.dept_name as department_name, u.real_name as operator_user_name
from biz_finance_expense e
left join biz_instrument i on i.id = e.instrument_id
left join sys_department d on d.id = e.department_id
left join sys_user u on u.id = e.operator_user_id
where 1 = 1

  and (e.expense_no like concat('%', #{keyword}, '%')
  or e.title like concat('%', #{keyword}, '%')
  or e.remark like concat('%', #{keyword}, '%')
  or i.instrument_name like concat('%', #{keyword}, '%'))


  and e.expense_type = #{expenseType}


  and e.instrument_id = #{instrumentId}


  and e.department_id = #{departmentId}


  and e.expense_time >= #{startTime}


  and e.expense_time <= #{endTime}


  and e.department_id = #{scopeDepartmentId}

order by e.expense_time desc, e.id desc
limit #{offset}, #{pageSize}

select count(1)
from biz_finance_expense e
left join biz_instrument i on i.id = e.instrument_id
where 1 = 1

  and (e.expense_no like concat('%', #{keyword}, '%')
  or e.title like concat('%', #{keyword}, '%')
  or e.remark like concat('%', #{keyword}, '%')
  or i.instrument_name like concat('%', #{keyword}, '%'))


  and e.expense_type = #{expenseType}


  and e.instrument_id = #{instrumentId}


  and e.department_id = #{departmentId}


  and e.expense_time >= #{startTime}


  and e.expense_time <= #{endTime}


  and e.department_id = #{scopeDepartmentId}

select coalesce(sum(e.amount), 0)
from biz_finance_expense e
where 1 = 1

  and e.expense_time >= #{startTime}


  and e.expense_time <= #{endTime}


  and e.department_id = #{scopeDepartmentId}

select coalesce(sum(e.amount), 0)
from biz_finance_expense e
where year(e.expense_time) = #{budgetYear}

  and e.department_id = #{departmentId}


  and e.instrument_id = #{instrumentId}


  and e.department_id = #{scopeDepartmentId}
